import styled from "styled-components";

export const ContainerPedidos = styled.div`
    color: #202020;
    display: flex;
    height: fit-content;
    min-height: calc(100vh - 130px);
    justify-content: space-between;
    text-align: center;
    padding: 15px 15px;
`;

export const ContainerProdutos = styled.div`
    color: #202020;
    display: flex;
    height: fit-content;
    min-height: calc(100vh - 130px);
    justify-content: space-around;
    align-items: center;
    width: 100%;
    text-align: center;
    padding: 15px 15px;
`;

export const BtnAdd = styled.button`
    display: flex;
    border: 1px solid black;
    background-color: rgba(61, 255, 37, 0.6);
    border-radius: 50%;
    position: absolute;
    font-size: 2em;
    padding: 15px;
    bottom: 8%;
    right: 5%;
    transition: .2s;

    :hover{
        scale: 1.1;
        cursor: pointer;
    }
`;
